external_knowledge:
- Top-performing players are determined by the most goals scored and assists; 
- Team positions are directly related to their points, goals for, and goals against in the season;
- Access logs are related to how many times a user has accessed the data.

sql:
SELECT p.player_name, p.market_value
FROM players p
INNER JOIN player_statistics ps ON p.player_id = ps.player_id;

SELECT 
  (SELECT SUM(market_value) FROM players) AS total_market_value,
  (SELECT COUNT(*) FROM teams) AS number_of_teams;
